COPY public.lead_bantc_question_guides (id, lead_id, questions, ai_generated, ai_model, updated_by, created_at, updated_at) FROM stdin;
1	137	[{"id":"n1","text":"Saat ini bagaimana cara tim di PT. Wira Pamungkas Pariwara berkolaborasi dan berkomunikasi untuk mengelola berbagai project dan akun klien sekaligus?","category":"Need","order":1},{"id":"n2","text":"Apa tantangan terbesar yang Anda lihat dalam komunikasi internal dan koordinasi lintas divisi saat menjalankan kampanye marketing untuk beberapa klien sekaligus?","category":"Need","order":2},{"id":"n3","text":"Bisakah Anda ceritakan bagaimana proses pengelolaan task dan project klien dilakukan sekarang, mulai dari brief, eksekusi hingga pelaporan ke klien?","category":"Need","order":3},{"id":"n4","text":"Jika dalam 6\\u201312 bulan ke depan tidak ada perubahan pada cara tim berkolaborasi dan mengelola project, dampak apa yang paling Anda khawatirkan terhadap kepuasan klien dan kinerja bisnis agensi?","category":"Need","order":4},{"id":"b1","text":"Untuk inisiatif peningkatan kolaborasi internal dan manajemen project, biasanya anggarannya masuk ke pos mana dan bagaimana proses penetapan budget di PT. Wira Pamungkas Pariwara?","category":"Budget","order":5},{"id":"b2","text":"Di kisaran berapa investasi tahunan yang masih dianggap realistis untuk platform kolaborasi dan manajemen operasi, jika solusi tersebut bisa membantu efisiensi pengelolaan akun klien dan project agensi?","category":"Budget","order":6},{"id":"b3","text":"Ketika menilai investasi untuk platform seperti Lark, indikator ROI seperti apa yang paling penting bagi Anda\\u2014misalnya penghematan waktu, pengurangan meeting, atau peningkatan kepuasan klien?","category":"Budget","order":7},{"id":"a1","text":"Selain Pak Yudi sebagai Direktur, siapa saja pihak kunci di PT. Wira Pamungkas Pariwara yang biasanya terlibat dalam keputusan memilih platform kolaborasi dan operasi baru?","category":"Authority","order":8},{"id":"a2","text":"Bagaimana alur pengambilan keputusan di perusahaan Anda ketika ingin mengadopsi tools baru untuk komunikasi internal dan manajemen project\\u2014dari tahap eksplorasi hingga persetujuan akhir?","category":"Authority","order":9},{"id":"a3","text":"Apakah ada tim IT, procurement, atau legal yang perlu dilibatkan lebih awal ketika kita mulai membahas implementasi platform seperti Lark di lingkungan PT. Wira Pamungkas Pariwara?","category":"Authority","order":10},{"id":"t1","text":"Apakah saat ini ada momentum atau target tertentu\\u2014misalnya penutupan tahun fiskal, peluncuran kampanye besar, atau restrukturisasi tim\\u2014yang membuat Anda ingin meningkatkan cara tim berkolaborasi?","category":"Timeline","order":11},{"id":"t2","text":"Jika solusi yang tepat ditemukan, kapan idealnya Anda ingin tim di PT. Wira Pamungkas Pariwara sudah mulai menggunakan platform kolaborasi dan operasi yang baru secara penuh?","category":"Timeline","order":12},{"id":"t3","text":"Langkah-langkah apa saja yang Anda bayangkan perlu dilalui dari sekarang sampai implementasi, dan berapa lama kira-kira waktu yang dibutuhkan di setiap tahap tersebut?","category":"Timeline","order":13},{"id":"c1","text":"Saat ini tools apa saja yang tim Anda gunakan untuk chat, meeting online, penyimpanan file, dan manajemen task\\/project, dan apa yang Anda suka maupun kurang suka dari solusi yang ada sekarang?","category":"Competition","order":14},{"id":"c2","text":"Jika Anda membandingkan beberapa opsi platform kolaborasi, kriteria apa yang paling penting bagi PT. Wira Pamungkas Pariwara dan apa risiko yang Anda lihat jika harus berpindah dari solusi yang digunakan saat ini?","category":"Competition","order":15}]	t	gpt-5.1	2	2026-05-30 04:15:53	2026-05-30 04:15:53
\.
